// Filtra eventos de Evolution API (MESSAGES_UPSERT)
// - Detecta comandos de administracion ("parar"/"seguir") escritos en el
//   grupo de escalamiento del equipo
// - Separa audios de texto para el resto de los clientes
const body = $json.body ?? $json;
const data = body.data;

if (!data || !data.key || data.key.fromMe) {
  return [];
}

const remoteJid = String(data.key.remoteJid);
const isGroup = remoteJid.endsWith('@g.us');
const msg = data.message || {};
const text = (msg.conversation || msg.extendedTextMessage?.text || '').trim();

if (isGroup) {
  const escalationGroup = 'TU_GRUPO_JID_AQUI@g.us';
  if (remoteJid === escalationGroup) {
    const normalized = text.trim().toLowerCase();
    const m = normalized.match(/^(parar|seguir)(?:\s+(\d{6,15}))?$/);
    if (m) {
      const command = m[1] === 'parar' ? 'paused' : 'active';
      const targetNumber = m[2] || null;
      return [{
        json: {
          type: 'admin_command',
          command,
          scope: targetNumber ? 'customer' : 'global',
          targetNumber,
          instance: body.instance,
          messageId: data.key.id
        }
      }];
    }
  }
  // Cualquier otro mensaje de grupo (o texto sin reconocer en el grupo del equipo) se ignora
  return [];
}

const isAudio = !!(msg.audioMessage || msg.pttMessage);
const isImage = !!(msg.imageMessage);
const caption = msg.imageMessage?.caption || '';
const finalText = text || caption.trim();

if (!isAudio && !isImage && !finalText) {
  return [];
}

return [{
  json: {
    type: 'customer_message',
    sessionId: remoteJid,
    number: remoteJid.split('@')[0],
    text: finalText,
    instance: body.instance,
    pushName: data.pushName || '',
    isAudio,
    isImage,
    messageId: data.key.id
  }
}];

// Deja pasar solo si el mensaje es un audio
if (!$json.isAudio) return [];
return [{ json: $json }];

// Deja pasar solo si el mensaje es texto (no audio, no imagen)
if ($json.isAudio || $json.isImage) return [];
return [{ json: $json }];

