const d = $('Es nuevo').first().json;
if (d.type !== 'customer_message') return [];
const numberLast10 = String(d.number || '').replace(/\D/g, '').slice(-10);
return [{ json: { ...d, numberLast10 } }];

const globalRows = $('Leer estado bot').all().map(i => i.json).filter(r => r && r.content);
const globalStatus = globalRows.length ? globalRows[0].content : 'active';

const customerRows = $input.all().map(i => i.json).filter(r => r && r.content);
const customerStatus = customerRows.length ? customerRows[0].content : 'active';

if (globalStatus === 'paused' || customerStatus === 'paused') return [];
return [{ json: $('Es mensaje cliente').first().json }];

const d = $('Es nuevo').first().json;
if (d.type !== 'admin_command') return [];
const last10 = s => String(s || '').replace(/\D/g, '').slice(-10);
const sessionIdKey = d.scope === 'customer'
  ? ('__paused_customer__:' + last10(d.targetNumber))
  : '__bot_status__';
return [{ json: { ...d, sessionIdKey } }];

