  number: 'TU_GRUPO_JID_AQUI@g.us',
  text: (() => {
    const d = $('Es comando admin').first().json;
    const paused = d.command === 'paused';
    if (d.scope === 'customer') {
      return paused
        ? '⏸️ Bot pausado SOLO para +' + d.targetNumber + '. Sigue respondiendo normal a los demás clientes. Escribí "seguir ' + d.targetNumber + '" cuando termines.'
        : '▶️ Bot reanudado para +' + d.targetNumber + '.';
    }
    return paused
      ? '⏸️ Bot pausado. No le va a responder a los clientes hasta que alguien escriba "seguir" en este grupo.'
      : '▶️ Bot reanudado. Ya vuelve a responder a los clientes normalmente.';
  })()
}) }}

