// Convierte el array replyParts en items separados para mandarlos
// como mensajes independientes de WhatsApp
const ctx = $('Extraer respuesta').first().json;
const parts = Array.isArray(ctx.replyParts) && ctx.replyParts.length ? ctx.replyParts : [ctx.reply];
return parts.map(text => ({ json: { number: ctx.number, instance: ctx.instance, text } }));

// Si ya existe un registro con este messageId, es un evento duplicado
// (Evolution/WhatsApp a veces reenvia el mismo webhook)
// Nota: alwaysOutputData hace que el nodo anterior siempre devuelva un
// item aunque no haya filas, por eso filtramos objetos vacios.
const rows = $input.all().map(i => i.json).filter(r => r && Object.keys(r).length > 0);
if (rows.length > 0) return [];
return [{ json: $('Filtrar y extraer').first().json }];

